import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,f as e}from"./app-d9d82146.js";const t={},p=e(`<h3 id="对象理解" tabindex="-1"><a class="header-anchor" href="#对象理解" aria-hidden="true">#</a> 对象理解</h3><ol><li>什么是对象?多个数据(属性)的集合。在 JavaScript 中，对象是一组无序的相关属性和方法的集合。</li><li>操作内部属性？通过<code>.属性名与[&#39;属性名&#39;]</code></li><li>对象的创建</li></ol><blockquote><p>a. Object构造函数模式：先创建空Object对象, 再动态添加属性/方法；<br> b. 对象字面量模式：使用{}创建对象, 同时指定属性/方法；<br> c. 工厂模式：工厂函数是返回一个对象的函数，通过工厂函数动态创建对象并返回；<br> d. 构造函数模式：自定义构造函数, 通过new创建对象；<br> e. 构造函数+原型的组合模式：自定义构造函数, 属性在函数中初始化, 方法添加到原型</p></blockquote><ol start="4"><li>对象类型（引用数据类型）</li></ol><blockquote><p>a. 标准普通对象 <code>object</code><br> b. 标准特殊对象 <code>Date Array RegExp Math Error</code><br> c. 非标准特殊对象 <code>Number Boolean String</code><br> d. 可调用对象 <code>function</code></p></blockquote><ol start="5"><li>内置对象是什么？存在全局作用域里的由 js 定义的一些全局值属性、函数、构造函数。全局函数如 parseInt()、parseFloat()；用来实例化对象的构造函数如 Date、Object 等，还有Math对象等</li><li>标准内置对象</li></ol><blockquote><p>a. 原始值:<code>undefined, null, number, string, boolean</code>;引用值: <code>object</code><br> b. 包装对象:<code>Number, String, Boolean; </code><br> c. 构造函数:<code>Object, Function, Date, Error, RegExP, Array Math JSON Arguments</code><br> d. 使用键的集合对象，如 <code>Map、Set、WeakMap、WeakSet</code><br> e. 可索引的集合对象，如 <code>Array</code><br> f. 控制抽象对象，如<code> Promise、Generator</code> 等</p></blockquote><h3 id="对象遍历" tabindex="-1"><a class="header-anchor" href="#对象遍历" aria-hidden="true">#</a> 对象遍历</h3><ol><li><code>for in</code>循环时返回的是存在于实例中的属性，也包括存在于原型中的实例。</li><li><code>Object.keys</code> =&gt; 获取对象自身所有的可枚举的属性值，返回一个由属性名组成的数组。</li><li><code>Object.values</code> =&gt; 获取对象自身所有的可枚举的属性值，返回一个由值组成的数组。</li><li><code>Object.entries</code>=&gt; 获取对象自身所有的可枚举的属性值，返回二维数组。</li><li><code>Object.getOwnPropertyNames</code>用于获取对象自身所有的可枚举的属性值，返回一个由属性名组成的数组。</li><li><code>Object.defineProperty()</code>定义对象中新属性或修改原有的属性。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Object.defineProperty(obj, prop, descriptor)\` descriptor 对象的参数值均为默认值</span>
Object<span class="token punctuation">.</span><span class="token function">defineProperty</span><span class="token punctuation">(</span>obj<span class="token punctuation">,</span> prop<span class="token punctuation">,</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">value</span><span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span><span class="token comment">//设置属性的值</span>
    <span class="token literal-property property">writable</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span><span class="token comment">//值是否可以重写。</span>
    <span class="token literal-property property">enumerable</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span><span class="token comment">//目标属性是否可以被枚举</span>
    <span class="token literal-property property">configurable</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token comment">//目标属性是否可以被删除或是否可以再次修改特性</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>  
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数组理解与使用" tabindex="-1"><a class="header-anchor" href="#数组理解与使用" aria-hidden="true">#</a> 数组理解与使用</h3><ol><li>数组是用一个变量存储多个数据的一种特殊的数据结构，可以通过数组下标获取对应位置的数据；</li><li>数组的常用API? ① 改变原数组：<code>pop push shift unshift reserve sort splice</code>； ② 不改变原数组：<code>slice concat toString toLocalString join</code></li><li>数组的遍历方式由哪些？</li></ol><blockquote><ul><li><code>forEach、for循环与for..of</code>：for速度最快；forEach 无法跳出循环；for 和 for ..of 可以使用 break 或者 continue 跳过或中断,不能return;</li><li><code>some every</code>:返回一个布尔值，<code>some</code>如果数组有某个元素满足回调那么就返回true; <code>every</code>如果数组所有元素满足回调那么就返回true</li><li><code>find、findIndex</code>: 查找数组元素，找到第一个满足回调的元素（元素Index）并返回</li><li><code>filter、map</code> 不会改变原数组, <code>filter</code>将回调函数的返回值为true的数组元素放进新数组并返回；<code>map</code>返回一个由回调函数的返回值组成的新数组</li><li><code>reduce、reduceRight</code>：从左到右为每个元素执行一次回调，并把上次回调的返回值缓存起来传给下次回调，返回最后一次的回调函数的返回值</li></ul></blockquote><ol start="4"><li>手写基本实现</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 手写map方法</span>
<span class="token keyword">function</span> <span class="token function">map</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">let</span> res <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">//返回一个由回调函数的返回值组成的新数组</span>
        res<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">)</span> 
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> res<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// 2 手写filter方法</span>
<span class="token keyword">function</span> <span class="token function">filter</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">let</span> res <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 将回调函数的返回值为true的数组元素放进新数组</span>
        <span class="token keyword">let</span> flag <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span>flag<span class="token punctuation">)</span> res<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> res<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// 3 手写find方法</span>
<span class="token keyword">function</span> <span class="token function">find</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">let</span> res <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 找到第一个满足回调函数的元素并返回那个元素</span>
        <span class="token keyword">let</span> flag <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span>flag<span class="token punctuation">)</span> <span class="token keyword">return</span> array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token comment">// 4 手写some方法</span>
<span class="token keyword">function</span> <span class="token function">some</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 有回调函数的返回值为true则返回true</span>
        <span class="token keyword">let</span> flag <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span>flag<span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// 5 手写every方法</span>
<span class="token keyword">function</span> <span class="token function">every</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 有回调函数的返回值为false就立马返回false</span>
        <span class="token keyword">let</span> flag <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">,</span> index<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span><span class="token punctuation">(</span><span class="token operator">!</span>flag<span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// 6 reduce理解：循环数组中的每一项，每次循环都会触发回调的执行，可以实现累加</span>
<span class="token keyword">let</span> arr<span class="token operator">=</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> total <span class="token operator">=</span> arr<span class="token punctuation">.</span><span class="token function">reduce</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">res<span class="token punctuation">,</span>item<span class="token punctuation">,</span>index</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span><span class="token keyword">return</span> res <span class="token operator">+</span> item<span class="token punctuation">;</span><span class="token punctuation">}</span><span class="token punctuation">)</span> 
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>total<span class="token punctuation">)</span> <span class="token comment">//10 </span>
<span class="token comment">// 过程分析：第一次:res=1 item=2 返回:3; 第二次:res=3 item=3 返回:6; 第三次:res=6 item=4,返回:10迭代完成</span>
<span class="token comment">// 7 手写reduce方法</span>
<span class="token keyword">function</span> <span class="token function">reduce</span><span class="token punctuation">(</span><span class="token parameter">array<span class="token punctuation">,</span> callback<span class="token punctuation">,</span> initVal</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">let</span> res <span class="token operator">=</span> initVal<span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> array<span class="token punctuation">.</span>length<span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 调用回调函数将返回的结果赋值给res</span>
        res <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>res<span class="token punctuation">,</span> array<span class="token punctuation">[</span>index<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> res<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数组与类数组的类别-怎么转化成数组" tabindex="-1"><a class="header-anchor" href="#数组与类数组的类别-怎么转化成数组" aria-hidden="true">#</a> 数组与类数组的类别，怎么转化成数组？</h3><ol><li>类数组是什么?<br> a. 属性要为索引（数字）属性；必须有length属性；不能使用数组的操作方法，比如push pop slice等<br> b. 常见的类数组对象有: 函数的arguments属性；DOM操作：document.querySelectorAll()获取nodeList。</li><li>怎么转化成数组?</li></ol><blockquote><p>a. 创建新数组，用for循环push进去新的数组<br> b. 通过Array.from 方法来实现转换<code>Array.from(arrayLike) Array.from(arguments);</code><br> c. es6展开运算符（rest参数<code>[...arguments]</code><br> d. 通过 call 调用数组的 slice 方法来实现转换<code>Array.prototype.slice.call(arrayLike);</code><br> e. 利用concat+apply, 通过 apply 调用数组的 concat 方法来实现转换<code>Array.prototype.concat.apply([], arguments)</code></p></blockquote><h3 id="set与weakset" tabindex="-1"><a class="header-anchor" href="#set与weakset" aria-hidden="true">#</a> Set与WeakSet</h3><ol><li>Array和Set的区别：元素可重复性，Set不可重复；元素序列，Array有序</li><li>WeakSet的弱集合：垃圾回收是一种内存管理技术。在这种技术中，不再被引用的对象会被自动删除，而与其相关的资源也会被一同回收。Set中对象的引用都是强类型化的，并不会允许垃圾回收。WeakSet它们允许从内存中清除不再需要的被这些集合所引用的对象。</li><li>WeakSet与Set的区别？</li></ol><blockquote><p>a. 存储类型:Set可以存储值类型和对象引用类型，而WeakSet只能存储对象引用类型，否则会抛出TypeError。<br> b. api方法：WeakSet对象是不可枚举的，也就是说无法获取大小，也无法获取其中包含的元素。只能使用add delete方法，遍历方法不能使用<br> c. 内存管理:set存储在set中的对象会保持引用; WeakSet弱引用(不会计数)，无引用的对象会被自动清除出集合（垃圾回收机制）。</p></blockquote><h3 id="函数的理解和使用" tabindex="-1"><a class="header-anchor" href="#函数的理解和使用" aria-hidden="true">#</a> 函数的理解和使用？</h3><ol><li>什么是函数? 用来实现特定功能的, n条语句的封装体，只有函数类型的数据是可以执行的。</li><li>函数定义? ① 函数声明方式 <code>function</code> 关键字 (命名函数); ② 函数表达式 (匿名函数)：<code>let func = function() {};</code></li><li>函数调用：① <code>test()</code>一般函数是直接调用；② 构造函数是通过new调用<code>new test()</code>；③ 通过.调用对象内部的属性/方法<code>p.test()</code>；④ 通过call/apply指定谁调用:<code> xxx.call(obj)</code>；</li></ol><blockquote><p>a. 普通函数：<code>fn()</code>,this指向window<br> b. 对象的方法：<code>obj.fn()</code>，this指向该方法所属对象<br> c. 构造函数：<code>new test()</code>，new构造函数this指向实例对象，原型里面的方法也指向实例对象<br> d. 通过call/apply调用: <code>xxx.call(thisArg, arg1, arg2)</code>：在fun函数运行时改变函数的this值<br> e. 绑定事件函数：触发相应事件，例如 <code>click</code>点击触发函数，this指向绑定事件对象<br> f. 定时器函数：<code>setInterval</code>每隔一段时间调用函数，this指向window<br> g. 立即执行函数：<code>(function() {})()</code>自动调用直接执行，this指向window</p></blockquote>`,24),o=[p];function c(l,i){return s(),a("div",null,o)}const k=n(t,[["render",c],["__file","JavaScript的对象数组函数.html.vue"]]);export{k as default};
